// ── GEOMETRY HELPERS ──
// Perpendicular distance (metres) from point P to segment AB
function ptSegDistM(pLa,pLo,aLa,aLo,bLa,bLo){
  var cosLat=Math.cos((pLa+aLa)*Math.PI/360);
  var px=(pLo-aLo)*cosLat*111320, py=(pLa-aLa)*111320;
  var bx=(bLo-aLo)*cosLat*111320, by=(bLa-aLa)*111320;
  var len2=bx*bx+by*by;
  if(len2===0)return Math.sqrt(px*px+py*py);
  var t=Math.max(0,Math.min(1,(px*bx+py*by)/len2));
  var dx=px-t*bx, dy=py-t*by;
  return Math.sqrt(dx*dx+dy*dy);
}
// Minimum distance (metres) from a point to a polyline
function ptPolyDistM(pLa,pLo,path){
  var minD=Infinity;
  for(var i=0;i<path.length-1;i++){
    var d=ptSegDistM(pLa,pLo,path[i][0],path[i][1],path[i+1][0],path[i+1][1]);
    if(d<minD)minD=d;
  }
  return minD;
}
// Great-circle distance (metres) between two points
function llDistM(la1,lo1,la2,lo2){
  var cosLat=Math.cos((la1+la2)*Math.PI/360);
  var dy=(la2-la1)*111320, dx=(lo2-lo1)*cosLat*111320;
  return Math.sqrt(dx*dx+dy*dy);
}

// ── DMP SCENARIO MATCHING ──
// routes: array of route strings (all affected routes for the disruption)
// Returns scenarios sorted by descending match score.
// Score components:
//   routeScore   — how many of the scenario's routes overlap with affected routes (0–1)
//   corridorHit  — 1 if disruption is within corridor buffer, else 0
//   anchorDist   — distance (m) from disruption to scenario's section anchor (lower = better)
function getDmpScenarios(routes, disLa, disLo){
  // Accept legacy single-route string for backwards compat
  if(typeof routes==='string') routes=[routes];

  // Precompute which corridor(s) the disruption falls on
  var hitCorridors={};
  var corridorDist={};
  Object.keys(DMP_CORRIDORS).forEach(function(key){
    var c=DMP_CORRIDORS[key];
    var d=ptPolyDistM(disLa,disLo,c.path);
    corridorDist[key]=d;
    if(d<=c.buffer) hitCorridors[key]=d;
  });

  var scored=[];
  DMP_DATA.forEach(function(s){
    // Route overlap: how many of this scenario's routes match the disruption's affected routes
    var overlap=s.rt.filter(function(r){return routes.indexOf(r)>=0;}).length;
    if(overlap===0) return; // no route overlap at all — skip

    var routeScore=overlap/Math.max(s.rt.length,routes.length);

    // Corridor check
    var pfx=s.id.split('.')[0];
    var isNumeric=!isNaN(parseInt(pfx));
    var corridorScore=0, anchorDist=9999;

    if(isNumeric){
      // Route-specific scenario (not corridor-based) — passes corridor check automatically
      corridorScore=1;
      // Use the scenario's own anchor if available, otherwise no anchor penalty
      var anc=DMP_ANCHORS[s.id];
      anchorDist=anc?llDistM(disLa,disLo,anc[0],anc[1]):500;
    } else {
      // Corridor scenario — must fall within this corridor's buffer
      var dist=corridorDist[pfx];
      if(dist===undefined||dist>DMP_CORRIDORS[pfx].buffer) return; // outside corridor
      // Score inversely by distance: 1.0 at 0m, 0 at buffer edge
      corridorScore=1-(dist/DMP_CORRIDORS[pfx].buffer);
      var anc=DMP_ANCHORS[s.id];
      anchorDist=anc?llDistM(disLa,disLo,anc[0],anc[1]):500;
    }

    // Composite score (weights: route 40%, corridor proximity 30%, anchor proximity 30%)
    // anchorDist normalised: 0m=1.0, 2000m+=0.0
    var anchorScore=Math.max(0,1-anchorDist/2000);
    var total=routeScore*0.40 + corridorScore*0.30 + anchorScore*0.30;

    scored.push({s:s, score:total, anchorDist:Math.round(anchorDist), corridorDist:Math.round(corridorDist[pfx]||0)});
  });

  // Sort by score descending
  scored.sort(function(a,b){return b.score-a.score;});
  return scored;
}

// Render ops/tt bullet array (array of strings, some may be [label] markers)
function renderBullets(arr) {
  if (!arr || arr.length === 0) return '<div class="dmp-no-data">No data available</div>';
  var h = '';
  arr.forEach(function(b) {
    if (b.startsWith('[') && b.endsWith(']')) {
      h += '<div class="dmp-opt-lbl">' + b.slice(1,-1) + '</div>';
    } else {
      // Strip leading bullet char
      var txt = b.replace(/^[••]\s*/, '');
      h += '<div class="dmp-bullet">' + txt + '</div>';
    }
  });
  return h;
}

window.openDmpPanel = function(disId) {
  var dis = window.disruptions.find(function(d){ return d.id === disId; });
  if (!dis) return;
  var affRoutes = dis.routes||[dis.route];
  var scoredMatches = getDmpScenarios(affRoutes, dis.la, dis.lo);

  var panel = document.getElementById('dmpPanel');
  var ctx   = document.getElementById('dmpCtx');
  var list  = document.getElementById('dmpScenList');

  // Context header — show all affected routes
  var routeLabels = affRoutes.map(function(r){
    var c=window.R[r]?R[r].c:'#888';
    return '<span style="color:'+c+'">Rt '+r+'</span>';
  }).join(' / ');
  ctx.innerHTML = '<b>Disruption #' + dis.id + '</b> &nbsp;' + routeLabels +
    ' &nbsp;&bull;&nbsp; ' + dis.type + '<br>' +
    '<span style="color:var(--tx3)">' + scoredMatches.length + ' scenario' +
    (scoredMatches.length !== 1 ? 's' : '') + ' matched</span>';

  if (scoredMatches.length === 0) {
    list.innerHTML = '<div class="dmp-empty">No DMP scenarios found for this location and route combination</div>';
  } else {
    var h = '';
    scoredMatches.forEach(function(m) {
      var s = m.s;
      var conf = m.score>=0.65?'HIGH':m.score>=0.40?'MED':'LOW';
      var confCol = conf==='HIGH'?'#69f0ae':conf==='MED'?'#f5a623':'#ff5252';
      var bodyId = 'dmpBody_' + s.id.replace(/\./g,'_');
      var arrId  = 'dmpArr_'  + s.id.replace(/\./g,'_');

      h += '<div class="dmp-sc">';
      h += '<div class="dmp-sc-hdr" onclick="toggleDmpCard(\'' + bodyId + '\',\'' + arrId + '\')">';
      h +=   '<span class="dmp-sc-id">' + s.id + '</span>';
      h +=   '<span class="dmp-sc-loc">' + (s.loc || '—') + '</span>';
      h +=   '<span style="font-family:\'JetBrains Mono\',monospace;font-size:8px;color:'+confCol+';white-space:nowrap;margin-right:4px">'+conf+'</span>';
      h +=   '<span class="dmp-sc-arr" id="' + arrId + '">&#x25B6;</span>';
      h += '</div>';

      h += '<div class="dmp-sc-body" id="' + bodyId + '">';

      // Match detail row
      h += '<div style="font-size:9px;color:var(--tx3);padding:2px 0 6px;border-bottom:1px solid var(--bdr);margin-bottom:4px">';
      h += 'Match score: <span style="color:'+confCol+'">'+Math.round(m.score*100)+'%</span>';
      if(m.anchorDist<9999) h += ' &nbsp;·&nbsp; ~'+m.anchorDist+'m from anchor';
      h += '</div>';

      h += '<div class="dmp-section-lbl">Operations</div>';
      h += renderBullets(s.ops);

      if (s.cse) {
        h += '<div class="dmp-section-lbl">CSE Locations</div>';
        h += '<div class="dmp-cse">' + s.cse.replace(/^[••]\s*/, '') + '</div>';
      }
      if (s.rep && s.rep !== 'N/A') {
        h += '<div class="dmp-section-lbl">Replacement Buses</div>';
        h += '<div class="dmp-cse">' + s.rep + '</div>';
      }
      if (s.tt && s.tt.length) {
        h += '<div class="dmp-section-lbl">TramTRACKER Text</div>';
        h += renderBullets(s.tt);
      }
      if (s.alt && s.alt.length) {
        h += '<div class="dmp-section-lbl">Alternative Transport</div>';
        s.alt.forEach(function(a) { h += '<div class="dmp-alt">&#x1F68C; ' + a + '</div>'; });
      }
      h += '<div class="dmp-meta">';
      if (s.dist) h += '<span class="dmp-meta-item"><b>Dist:</b> ' + s.dist + '</span>';
      h += '<span class="dmp-meta-item"><b>Metro:</b> ' + s.metro + '</span>';
      if (s.rep && s.rep !== 'N/A') h += '<span class="dmp-meta-item"><b>Rep bus:</b> Yes</span>';
      h += '</div>';
      h += '</div></div>';
    });
    list.innerHTML = h;

    // Auto-expand the top-scored scenario
    var firstBody = document.getElementById('dmpBody_' + scoredMatches[0].s.id.replace(/\./g,'_'));
    var firstArr  = document.getElementById('dmpArr_'  + scoredMatches[0].s.id.replace(/\./g,'_'));
    if (firstBody) firstBody.classList.add('open');
    if (firstArr)  firstArr.classList.add('open');
  }

  panel.classList.add('open');
};

window.toggleDmpCard = function(bodyId, arrId) {
  var body = document.getElementById(bodyId);
  var arr  = document.getElementById(arrId);
  if (!body) return;
  body.classList.toggle('open');
  if (arr) arr.classList.toggle('open');
};

window.closeDmpPanel = function() {
  document.getElementById('dmpPanel').classList.remove('open');
};

// ===== END DMP =====

window.getDmpScenarios=getDmpScenarios;
window.openDmpPanel=openDmpPanel;
window.closeDmpPanel=closeDmpPanel;
window.toggleDmpCard=toggleDmpCard;
window.renderBullets=renderBullets;
